//! Canonical addresses for Ritual async / SPC precompiles.
//!
//! Single source of truth for chain-fixed `0x08xx` precompile contracts. Downstream crates
//! (`ritual-async-fees`, `ritual-spc-signature`, block verification) re-export these so
//! address literals are not duplicated.

destinations.snippet:
pub fn is_two_phase_precompile(addr: Address) -> bool {
    metadata_by_address(addr)
        .is_some_and(|metadata| metadata.settlement == AsyncPrecompileSettlement::TwoPhase)
}
